arguments.file_text:
namespace sv_da4866148baf47f7977fae3bb69c5b4e.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_da4866148baf47f7977fae3bb69c5b4e.Components.Pages.Settings
@using sv_da4866148baf47f7977fae3bb69c5b4e.Services

<div class="profile-section">
    @if (IsLoading)
    {
        <div class="loading-spinner">Loading profile...</div>
    }
    else if (Profile is not null)
    {
        <h4>Profile Settings</h4>

        @if (!string.IsNullOrEmpty(StatusMessage))
        {
            <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <div class="profile-form">
            <div class="avatar-area mb-4">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(AvatarUrl))
                    {
                        <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <div class="avatar-url-display">
                    <label class="form-label">Avatar URL</label>
                    <input type="url" class="form-control" value="@AvatarUrl" disabled />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="DisplayName" />
            </div>

            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="Email" />
            </div>

            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="Bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
                    @if (IsSaving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@IsSaving">
                    Discard Changes
                </button>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private UserProfile? Profile { get; set; }
    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private string Bio { get; set; } = "";
    private bool IsLoading { get; set; } = true;
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        IsLoading = true;
        Profile = await SettingsService.GetProfileAsync();
        PopulateFields(Profile);
        IsLoading = false;
    }

    private void PopulateFields(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await SettingsService.SaveProfileAsync(updated);
            Profile = updated;
            StatusMessage = "Profile saved successfully!";
            IsError = false;
        }
        catch (Exception ex)
        {
            StatusMessage = $"Failed to save profile: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void DiscardChanges()
    {
        if (Profile is not null)
        {
            PopulateFields(Profile);
        }
        StatusMessage = null;
    }
}

.profile-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2.5rem;
}

.avatar-url-display {
    flex: 1;
    align-self: center;
}

.loading-spinner {
    text-align: center;
    padding: 3rem;
    color: #6c757d;
}

