    public ISettingsService SettingsService { get; set; } = default!;

    private UserProfile? Profile { get; set; }
    private string DisplayName { get; set; } = "";
    private string Email { get; set; } = "";
    private string AvatarUrl { get; set; } = "";
    private string Bio { get; set; } = "";
    private bool IsLoading { get; set; } = true;
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        IsLoading = true;
        Profile = await SettingsService.GetProfileAsync();
        PopulateFields(Profile);
        IsLoading = false;
    }

    private void PopulateFields(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await SettingsService.SaveProfileAsync(updated);
            Profile = updated;
            StatusMessage = "Profile saved successfully!";
            IsError = false;
        }
        catch (Exception ex)
        {
            StatusMessage = $"Failed to save profile: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void DiscardChanges()
    {
        if (Profile is not null)
        {
            PopulateFields(Profile);
        }
        StatusMessage = null;
    }
}

