@namespace sv_da4866148baf47f7977fae3bb69c5b4e.Components.Pages.Settings
@using sv_da4866148baf47f7977fae3bb69c5b4e.Services

<div class="notifications-section">
    @if (IsLoading)
    {
        <div class="loading-spinner">Loading notification preferences...</div>
    }
    else if (Prefs is not null)
    {
        <h4>Notification Preferences</h4>

        @if (!string.IsNullOrEmpty(StatusMessage))
        {
            <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <div class="toggle-group mb-4">
            <div class="toggle-item">
                <div>
                    <strong>Email Notifications</strong>
                    <p class="text-muted mb-0">Receive updates via email</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@EmailNotifications" @onchange="e => EmailNotifications = (bool)e.Value!" />
                </div>
            </div>

            <div class="toggle-item">
                <div>
                    <strong>Push Notifications</strong>
                    <p class="text-muted mb-0">Receive browser push notifications</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@PushNotifications" @onchange="e => PushNotifications = (bool)e.Value!" />
                </div>
            </div>

            <div class="toggle-item">
                <div>
                    <strong>Weekly Digest</strong>
                    <p class="text-muted mb-0">Get a weekly summary of activity</p>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@WeeklyDigest" @onchange="e => WeeklyDigest = (bool)e.Value!" />
                </div>
            </div>
        </div>

        <div class="channels-section mb-4">
            <h6>Muted Channels</h6>
            <p class="text-muted">Select channels to mute notifications from.</p>
            <div class="channels-list">
                @foreach (var channel in AvailableChannels)
                {
                    var isMuted = MutedChannels.Contains(channel);
                    <div class="form-check">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@isMuted"
                               @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private NotificationPrefs? Prefs { get; set; }
    private bool EmailNotifications { get; set; }
    private bool PushNotifications { get; set; }
    private bool WeeklyDigest { get; set; }
    private HashSet<string> MutedChannels { get; set; } = [];
    private bool IsLoading { get; set; } = true;
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }

    private static readonly string[] AvailableChannels =
        ["General", "Announcements", "Engineering", "Marketing", "Support", "Random"];

    protected override async Task OnInitializedAsync()
    {
        IsLoading = true;
        Prefs = await SettingsService.GetNotificationPrefsAsync();
        EmailNotifications = Prefs.EmailNotifications;
        PushNotifications = Prefs.PushNotifications;
        WeeklyDigest = Prefs.WeeklyDigest;
        MutedChannels = [.. Prefs.MutedChannels];
        IsLoading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            MutedChannels.Add(channel);
        else
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        try
        {
            var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            Prefs = updated;
            StatusMessage = "Notification preferences saved!";
            IsError = false;
        }
        catch (Exception ex)
        {
            StatusMessage = $"Failed to save: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }
}

.notifications-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 0;
    border-bottom: 1px solid #eee;
}

.toggle-item:first-child {
    padding-top: 0;
}

.toggle-item p {
    font-size: 0.85rem;
}

.channels-section h6 {
    font-weight: 600;
}

.channels-list {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 0.5rem;
}

.loading-spinner {
    text-align: center;
    padding: 3rem;
    color: #6c757d;
