                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@IsRevoking">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@IsRevoking">
                                @if (IsRevoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1"></span>
