{"file_text": "@namespace sv_da4866148baf47f7977fae3bb69c5b4e.Components.Pages.Settings
@using sv_da4866148baf47f7977fae3bb69c5b4e.Services

<div class="appearance-section">
    @if (IsLoading)
    {
        <div class="loading-spinner">Loading appearance settings...</div>
    }
    else
    {
        <h4>Appearance Settings</h4>

        @if (!string.IsNullOrEmpty(StatusMessage))
        {
            <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-7">
                <!-- Theme Selector -->
                <div class="mb-4">
                    <h6>Theme</h6>
                    <div class="d-flex gap-3">
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(SelectedTheme == theme)"
                                       @onchange="() => SelectedTheme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Font Size Selector -->
                <div class="mb-4">
                    <h6>Font Size</h6>
                    <div class="d-flex gap-3">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(SelectedFontSize == size)"
                                       @onchange="() => SelectedFontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <!-- Language Dropdown -->
                <div class="mb-4">
                    <h6>Language</h6>
                    <select class="form-select" style="max-width: 300px;" @bind="SelectedLanguage">
                        @foreach (var lang in AvailableLanguages)
                        {
                            <option value="@lang.Key">@lang.Value</option>
                        }
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="mb-4">
                    <div class="d-flex justify-content-between align-items-center" style="max-width: 300px;">
                        <div>
                            <h6 class="mb-0">Compact Mode</h6>
                            <small class="text-muted">Reduce spacing and padding</small>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@CompactMode" @onchange="e => CompactMode = (bool)e.Value!" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@IsSaving">
                    @if (IsSaving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save
                </button>
            </div>

            <!-- Live Preview -->
            <div class="col-md-5">
                <div class="preview-panel @GetPreviewClasses()">
                    <h6 class="preview-title">Live Preview</h6>
                    <div class="preview-content">
                        <div class="preview-header">Dashboard</div>
                        <p class="preview-text">This is how your interface will look with the selected settings.</p>
                        <div class="preview-card">
                            <div class="preview-card-title">Sample Card</div>
                            <div class="preview-card-body">Content appears here with your chosen theme and font size.</div>
                        </div>
                        <div class="preview-meta">
                            Language: @(AvailableLanguages.GetValueOrDefault(SelectedLanguage, SelectedLanguage)) ·
                            Compact: @(CompactMode ? "On" : "Off")
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool IsLoading { get; set; } = true;
    private bool IsSaving { get; set; }
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }

    private string SelectedTheme { get; set; } = "Light";
    private string SelectedFontSize { get; set; } = "Medium";
    private string SelectedLanguage { get; set; } = "en";
    private bool CompactMode { get; set; }

    private static readonly Dictionary<string, string> AvailableLanguages = new()
    {
        ["en"] = "English",
        ["es"] = "Español",
        ["fr"] = "Français",
        ["de"] = "Deutsch",
        ["ja"] = "日本語",
        ["zh"] = "中文"
    };

    protected override async Task OnInitializedAsync()
    {
        IsLoading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        SelectedTheme = settings.Theme;
        SelectedFontSize = settings.FontSize;
        SelectedLanguage = settings.Language;
        CompactMode = settings.CompactMode;
        IsLoading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(SelectedTheme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(SelectedFontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-small",
            "large" => "preview-font-large",
            _ => "preview-font-medium"
        });
        if (CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        IsSaving = true;
        StatusMessage = null;
        try
        {
            var settings = new AppearanceSettings(SelectedTheme, SelectedFontSize, SelectedLanguage, CompactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            StatusMessage = "Appearance settings saved!";
            IsError = false;
        }
        catch (Exception ex)
        {
            StatusMessage = $"Failed to save: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }
}
