toolArgs.file_text:
@namespace sv_da4866148baf47f7977fae3bb69c5b4e.Components.Pages.Settings
@using sv_da4866148baf47f7977fae3bb69c5b4e.Services

<div class="security-section">
    @if (IsLoading)
    {
        <div class="loading-spinner">Loading security settings...</div>
    }
    else if (Security is not null)
    {
        <h4>Security Settings</h4>

        @if (!string.IsNullOrEmpty(StatusMessage))
        {
            <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <!-- Change Password Panel -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor: pointer;" @onclick="() => PasswordPanelOpen = !PasswordPanelOpen">
                <strong>Change Password</strong>
                <span class="expand-icon">@(PasswordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (PasswordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="CurrentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="NewPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="ConfirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(PasswordError))
                    {
                        <div class="text-danger mb-3">@PasswordError</div>
                    }
                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@IsChangingPassword">
                        @if (IsChangingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <p class="text-muted mb-0">
                        @if (Security.TwoFactorEnabled)
                        {
                            <span class="badge bg-success me-2">Enabled</span>
                            <span>Your account is protected with 2FA.</span>
                        }
                        else
                        {
                            <span class="badge bg-secondary me-2">Disabled</span>
                            <span>Add an extra layer of security to your account.</span>
                        }
                    </p>
                    @if (Security.LastPasswordChange.HasValue)
                    {
                        <small class="text-muted">Last password change: @Security.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@Security.TwoFactorEnabled" disabled />
                </div>
            </div>
        </div>

        <!-- Active Sessions -->
        <div class="card mb-4">
            <div class="card-header">
                <strong>Active Sessions</strong>
            </div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in Security.Sessions)
                            {
                                var isCurrent = session == Security.Sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-primary ms-2">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (SessionToRevoke is not null)
        {
            <div class="modal-backdrop show"></div>
            <div class="modal d-block" tabindex="-1">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@SessionToRevoke.Device</strong> from <strong>@SessionToRevoke.Location</strong>?</p>
                            <p class="text-muted">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@IsRevoking">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@IsRevoking">
                                @if (IsRevoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1"></span>
                                }
                                Revoke Session
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? Security { get; set; }
    private bool IsLoading { get; set; } = true;
    private string? StatusMessage { get; set; }
    private bool IsError { get; set; }

    // Password change state
    private bool PasswordPanelOpen { get; set; }
    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private string? PasswordError { get; set; }
    private bool IsChangingPassword { get; set; }

    // Session revoke state
    private ActiveSession? SessionToRevoke { get; set; }
    private bool IsRevoking { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadSecurityAsync();
    }

    private async Task LoadSecurityAsync()
    {
        IsLoading = true;
        Security = await SettingsService.GetSecuritySettingsAsync();
        IsLoading = false;
    }

    private async Task ChangePasswordAsync()
    {
        PasswordError = null;
        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            PasswordError = "All password fields are required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            PasswordError = "New password and confirmation do not match.";
            return;
        }
        if (NewPassword.Length < 8)
        {
            PasswordError = "New password must be at least 8 characters.";
            return;
        }

        IsChangingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(CurrentPassword, NewPassword);
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
            PasswordPanelOpen = false;
            StatusMessage = "Password updated successfully!";
            IsError = false;
            await LoadSecurityAsync();
        }
        catch (Exception ex)
        {
            PasswordError = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            IsChangingPassword = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        SessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        SessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (SessionToRevoke is null) return;

        IsRevoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(SessionToRevoke.Id);
            StatusMessage = $"Session on {SessionToRevoke.Device} has been revoked.";
            IsError = false;
            SessionToRevoke = null;
            await LoadSecurityAsync();
        }
        catch (Exception ex)
        {
            StatusMessage = $"Failed to revoke session: {ex.Message}";
            IsError = true;
        }
        finally
        {
            IsRevoking = false;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return lastActive.ToString("MMM dd, yyyy HH:mm");
    }
}

