toolArgs.file_text:
.appearance-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.appearance-section h6 {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.loading-spinner {
    text-align: center;
    padding: 3rem;
    color: #6c757d;
}

/* Live Preview */
.preview-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    transition: all 0.2s ease;
}

.preview-title {
    padding: 0.75rem 1rem;
    margin: 0;
    border-bottom: 1px solid #dee2e6;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #6c757d;
    background: inherit;
}

.preview-content {
    padding: 1rem;
}

.preview-header {
    font-weight: 700;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 0.75rem;
}

.preview-card {
    border: 1px solid;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.75rem;
}

.preview-card-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.preview-card-body {
    font-size: 0.9em;
    opacity: 0.8;
}

.preview-meta {
    font-size: 0.8rem;
    opacity: 0.6;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-card {
    border-color: #dee2e6;
    background: #f8f9fa;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .preview-title {
    color: #a6adc8;
    border-color: #45475a;
}

.preview-dark .preview-card {
    border-color: #45475a;
    background: #313244;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #212529;
}

.preview-system .preview-content {
    background: #f0f0f5;
    color: #333;
}

.preview-system .preview-card {
    border-color: #ccc;
    background: #e8e8ed;
}

/* Font size variants */
.preview-font-small .preview-content {
    font-size: 0.8rem;
}

.preview-font-medium .preview-content {
    font-size: 0.95rem;
}

.preview-font-large .preview-content {
    font-size: 1.1rem;
}

/* Compact mode */
.preview-compact .preview-content {
    padding: 0.5rem;
    line-height: 1.3;
}

.preview-compact .preview-card {
    padding: 0.4rem;
    margin-bottom: 0.4rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.4rem;
}

