+    background: #f8f9fa;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+}
+
+.preview-dark .preview-title {
+    color: #a6adc8;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-card {
+    border-color: #45475a;
+    background: #313244;
+}
+
+.preview-system {
+    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
+    color: #212529;
+}
+
+.preview-system .preview-content {
+    background: #f0f0f5;
+    color: #333;
+}
+
+.preview-system .preview-card {
+    border-color: #ccc;
+    background: #e8e8ed;
+}
+
+/* Font size variants */
+.preview-font-small .preview-content {
+    font-size: 0.8rem;
+}
+
+.preview-font-medium .preview-content {
+    font-size: 0.95rem;
+}
+
+.preview-font-large .preview-content {
+    font-size: 1.1rem;
+}
+
+/* Compact mode */
+.preview-compact .preview-content {
+    padding: 0.5rem;
+    line-height: 1.3;
+}
+
+.preview-compact .preview-card {
+    padding: 0.4rem;
+    margin-bottom: 0.4rem;
+}
+
+.preview-compact .preview-text {
+    margin-bottom: 0.4rem;
+}
