arguments.file_text:
@page "/settings"
@using sv_da4866148baf47f7977fae3bb69c5b4e.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@ActiveSection" OnSectionSelected="section => ActiveSection = section" />

    <div class="settings-content">
        @switch (ActiveSection)
        {
            case "Profile":
                <ProfileSection SettingsService="SettingsService" />
                break;
            case "Notifications":
                <NotificationsSection SettingsService="SettingsService" />
                break;
            case "Security":
                <SecuritySection SettingsService="SettingsService" />
                break;
            case "Appearance":
                <AppearanceSection SettingsService="SettingsService" />
                break;
        }
    </div>
</div>

@code {
    private string ActiveSection { get; set; } = "Profile";
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 120px);
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

